import{_ as e,o as l,c as a,a1 as i}from"./chunks/framework.BX4nIuL2.js";const c=JSON.parse('{"title":"CMF 设计美学与规范 (Color, Material, Finish)","description":"","frontmatter":{},"headers":[],"relativePath":"courses/cmf.md","filePath":"courses/cmf.md"}'),s={name:"courses/cmf.md"};function r(n,t,o,d,f,g){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="cmf-设计美学与规范-color-material-finish" tabindex="-1">CMF 设计美学与规范 (Color, Material, Finish) <a class="header-anchor" href="#cmf-设计美学与规范-color-material-finish" aria-label="Permalink to &quot;CMF 设计美学与规范 (Color, Material, Finish)&quot;">​</a></h1><p>CMF 是定义工业产品最终质感、档次与用户触觉体验的核心规范。本指南主要阐述 ProFabX 移动机器人底盘及控制器外壳的金属加工与表面处理标准。</p><h2 id="_1-铝合金表面处理" tabindex="-1">1. 铝合金表面处理 <a class="header-anchor" href="#_1-铝合金表面处理" aria-label="Permalink to &quot;1. 铝合金表面处理&quot;">​</a></h2><p>铝合金外壳具备轻量化与优异的散热性能。在机械加工（CNC）完成后，需经历喷砂与化学处理：</p><ul><li><p><strong>喷砂粒度标准 (Sandblasting):</strong></p><ul><li>#120 号金刚砂: 质感粗犷，防滑耐磨，适用于户外机器人底盘侧板。</li><li>#180 号金刚砂: 质感细腻，触感柔和，适用于手持遥控器及上盖。</li></ul></li><li><p><strong>阳极氧化工艺 (Anodizing):</strong></p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>通过电化学方法，在铝合金表面生成一层致密且可染色的氧化铝保护膜。 我们的标准<strong>阳极氧化工艺</strong>要求膜厚达到 8μm - 12μm，以确保色彩均匀性与抗腐蚀寿命。 推荐色值包含：太空灰、极客黑与<strong>克莱因蓝 (#002FA7)</strong>。</p></div></li></ul><hr><h2 id="_2-涂装工艺参数对比" tabindex="-1">2. 涂装工艺参数对比 <a class="header-anchor" href="#_2-涂装工艺参数对比" aria-label="Permalink to &quot;2. 涂装工艺参数对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">工艺名称</th><th style="text-align:left;">表面硬度</th><th style="text-align:left;">耐磨性</th><th style="text-align:left;">生产成本</th><th style="text-align:left;">环保等级</th><th style="text-align:left;">适用部位</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>阳极氧化</strong></td><td style="text-align:left;">300-400 HV</td><td style="text-align:left;">极佳</td><td style="text-align:left;">中等</td><td style="text-align:left;">高</td><td style="text-align:left;">铝合金外壳</td></tr><tr><td style="text-align:left;"><strong>粉末喷涂</strong></td><td style="text-align:left;">2-3 H (铅笔)</td><td style="text-align:left;">良好</td><td style="text-align:left;">较低</td><td style="text-align:left;">中等</td><td style="text-align:left;">钢制防护栏</td></tr><tr><td style="text-align:left;"><strong>手感漆涂装</strong></td><td style="text-align:left;">&lt; 1 H</td><td style="text-align:left;">一般</td><td style="text-align:left;">较高</td><td style="text-align:left;">中等</td><td style="text-align:left;">遥控器手柄</td></tr></tbody></table><hr><h2 id="_3-问题与协作" tabindex="-1">3. 问题与协作 <a class="header-anchor" href="#_3-问题与协作" aria-label="Permalink to &quot;3. 问题与协作&quot;">​</a></h2><p>如果您对阳极氧化氧化膜的厚度控制或喷砂颗粒的型号选择有任何疑问，请使用鼠标在文档中<strong>划词</strong>发表您的疑问或查看他人的批注！</p>',11)])])}const x=e(s,[["render",r]]);export{c as __pageData,x as default};
